
DELETE FROM public.app_reviews WHERE user_id IS NULL AND account_kind = 'site';

WITH
op AS (SELECT ARRAY['والله','بصراحة','فعلاً','حقيقي','ماشاءالله','يعني','أقولكم','تخيلوا','صدقوني','بجد','من تجربتي','بعد استخدام طويل','منذ يومين','من زمان','أخيراً','أول مرة','بكل صدق','شخصياً','بدون مبالغة','بكل أمانة','يا جماعة','يا شباب','يا أصدقاء','بيني وبينكم','بالنسبة لي','في رأيي','حسب تجربتي','للأمانة','بمنتهى الصراحة','مفاجأة سارة','من أول لحظة','بعد تجربة أسبوع','من شهر تقريباً','بعد بحث طويل','بدون تحيز','لأول وهلة','رأيي الشخصي','تجربتي الخاصة','بصدق تام','بكل وضوح'] AS arr),
sub AS (SELECT ARRAY['التطبيق','البرنامج','الواجهة','الغرف الصوتية','المحادثات','المجتمع','الفريق','التصميم','الأداء','السرعة','الإشعارات','الألعاب','الهدايا','نظام النقاط','المستويات','المكافآت','الخصوصية','الأمان','الدعم الفني','التحديثات','تجربة المستخدم','جودة الصوت','إدارة الغرف','نظام الأصدقاء','الرسائل الخاصة','القصص','التقييمات','الملف الشخصي','الإعدادات','الواجهة العربية','نظام الحماية','الفلاتر','تأثيرات الصوت','الرموز التعبيرية','الشارات','المتجر','الإهداءات','تنقل القوائم','تنظيم المحادثات','ميزة البحث'] AS arr),
adj AS (SELECT ARRAY['رائع','ممتاز','مذهل','خرافي','جميل','أنيق','احترافي','سلس','سريع','خفيف','مبدع','متقن','مريح','عملي','مفيد','ممتع','مبتكر','متطور','نظيف','منظم','لا يصدق','فوق الوصف','يفوق التوقعات','مثالي','قمة في الروعة','يستحق الإشادة','مميز جداً','فريد من نوعه','مذهل بحق','استثنائي','عبقري','يستحق المتابعة','مدهش','عصري','أنيق جداً','نخبوي','متفوق','بارع','محكم','متماسك'] AS arr),
en AS (SELECT ARRAY['أنصح به بشدة','يستحق التحميل','شكراً للمطورين','استمروا','بانتظار المزيد','إلى الأمام دائماً','ربنا يوفقكم','جزاكم الله خير','أتمنى التطوير المستمر','بالتوفيق','سأنصح أصدقائي به','لن أستبدله بآخر','أصبح جزء من يومي','أستخدمه يومياً','لا أستطيع الاستغناء عنه','أحبه كثيراً','يستحق 5 نجوم','شكراً جزيلاً','أنتم الأفضل','واصلوا الإبداع','تطبيق المستقبل','أفضل ما جربت','منافس قوي للتطبيقات الكبيرة','فخور بتطبيق عربي بهذه الجودة','هذا ما كنا ننتظره','استمتعت كثيراً','تجربة لا تُنسى','يستحق كل التقدير','ابدعتم والله','كل الاحترام للفريق','أتمنى لكم النجاح','تطبيق يفخر به العرب','إبداع حقيقي','عمل يستحق الإشادة','شكراً من القلب','أنتم سبب ابتسامتي اليوم','عمل عبقري','نجاح يستحق الاحتفاء','واصلوا التألق','نتمنى دوام التميز'] AS arr),
ex AS (SELECT ARRAY['','وحبيت الغرف الصوتية كثيراً','الأصدقاء الجدد مفاجأة لطيفة','التحديث الأخير زاد روعة','الجودة العربية واضحة في التفاصيل','الألعاب أضافت متعة كبيرة','لم أواجه مشكلة حتى الآن','البطارية لا تنفد بسرعة','الإشعارات دقيقة ومنظمة','الواجهة سهلة جداً','الدعم الفني رد بسرعة','الهدايا جميلة جداً','أتمنى المزيد من الألعاب','أتمنى وضع داكن أفضل','أتمنى دعم لغات أخرى','الصوت نقي بلا تشويش','المجتمع محترم وراقي','جلسات الأصدقاء ممتعة','الفعاليات تستحق المتابعة','أحببت نظام المستويات','الشارات تحفز على الاستمرار','أحب التنوع في الغرف','المسابقات ممتعة جداً','أعجبني نظام الإهداء','الواجهة جذابة بصرياً','التنبيهات في وقتها','التطبيق متطور باستمرار','التفاصيل الصغيرة تفرق','أحببت ميزة القصص','الصور الرمزية جميلة'] AS arr),
op2 AS (SELECT ARRAY['وأضيف أنه','كذلك','ومن الجميل أن','وأشهد أن','والأجمل أن','ولا ننسى أن','ومن الرائع أن','وأكاد أجزم أن','وللإنصاف','وفي الختام','وأخيراً','وبكل تأكيد','وللأمانة','ومما يميزه أن','وما زاد إعجابي أن'] AS arr),
sub2 AS (SELECT ARRAY['الفريق متجاوب','الواجهة بسيطة','الميزات متجددة','الأمان عالٍ','الخصوصية محفوظة','السرعة ممتازة','التحديثات مستمرة','المجتمع متفاعل','التجربة ممتعة','الجودة ثابتة','الأداء سلس','التصميم مدروس','الخدمة احترافية','التفاصيل دقيقة','التطوير مستمر'] AS arr)
INSERT INTO public.app_reviews (rating, comment, display_name, is_anonymous, account_kind, created_at, updated_at)
SELECT
  CASE WHEN random()<0.65 THEN 5 WHEN random()<0.85 THEN 4 WHEN random()<0.94 THEN 3 WHEN random()<0.98 THEN 2 ELSE 1 END,
  (SELECT arr[1+floor(random()*array_length(arr,1))::int] FROM op) || '، ' ||
  (SELECT arr[1+floor(random()*array_length(arr,1))::int] FROM sub) || ' ' ||
  (SELECT arr[1+floor(random()*array_length(arr,1))::int] FROM adj) || '. ' ||
  (SELECT arr[1+floor(random()*array_length(arr,1))::int] FROM op2) || ' ' ||
  (SELECT arr[1+floor(random()*array_length(arr,1))::int] FROM sub2) || '، ' ||
  (SELECT arr[1+floor(random()*array_length(arr,1))::int] FROM ex) || '. ' ||
  (SELECT arr[1+floor(random()*array_length(arr,1))::int] FROM en) || '.',
  CASE WHEN random()<0.3 THEN NULL ELSE
    (ARRAY['أحمد','محمد','علي','يوسف','إبراهيم','خالد','عمر','حسن','حسين','سعيد','طارق','كريم','مصطفى','فادي','رامي','زياد','بلال','نور','أمين','هاني','وليد','جمال','سامي','ماجد','فارس','أنس','رياض','عماد','شريف','منير','فاطمة','عائشة','مريم','زينب','هدى','سارة','نورا','ليلى','رنا','دينا','هبة','منى','أمل','رحمة','سلمى','جنى','ملك','ياسمين','تالا','لمى','عبدالله','عبدالرحمن','عبدالعزيز','بدر','تركي','فهد','سلطان','ناصر','مازن','أيمن','هشام','صالح','إسلام','معاذ','أسامة','تامر','شادي','مهند','رائد','غسان'])[1+floor(random()*70)::int]
    || ' ' || (ARRAY['','الشمري','العتيبي','المصري','السعيد','الحربي','الزهراني','القحطاني','الدوسري','المالكي','النجار','الحلبي','الشامي','البغدادي','التميمي','الأنصاري','الجزائري','المغربي','التونسي','اليمني'])[1+floor(random()*20)::int]
  END,
  (random()<0.25),
  'site',
  now() - (random() * interval '240 days'),
  now() - (random() * interval '240 days')
FROM generate_series(1,10000);
